    #[test]
    fn sgr_colors() {
        assert_eq!(visible_width("\\x1b[31mred\\x1b[0m"), 3);
        assert_eq!(visible_width("\\x1b[1;32;44mbold green on blue\\x1b[0m"), 18);
    }

    #[test]
    fn sgr_256_color() {
        assert_eq!(visible_width("\\x1b[38;5;196mred256\\x1b[0m"), 6);
    }

    #[test]
    fn sgr_rgb_color() {
        assert_eq!(visible_width("\\x1b[38;2;255;0;0mrgb red\\x1b[0m"), 7);
    }

    // CSI (Control Sequence Introducer) sequences
    #[test]
    fn csi_cursor_movement() {
        assert_eq!(visible_width("\\x1b[10Ctext"), 4);  // Cursor forward
        assert_eq!(visible_width("\\x1b[2Jcleared"), 7);  // Clear screen
    }

    // OSC (Operating System Command) sequences
    #[test]
    fn osc_window_title() {
        assert_eq!(visible_width("\\x1b]0;My Title\\x07text"), 4);
        assert_eq!(visible_width("\\x1b]0;My Title\\x1b\\\\text"), 4);  // ST terminator
