        // OSC 8 hyperlinks
        assert_eq!(visible_width("\\x1b]8;;https://example.com\\x07link\\x1b]8;;\\x07"), 4);
    }

    // Edge cases
    #[test]
    fn empty_and_whitespace() {
        assert_eq!(visible_width(""), 0);
        assert_eq!(visible_width("   "), 3);
        assert_eq!(visible_width("\\t"), 1);  // Tab = 1 character
    }

    #[test]
    fn mixed_content() {
        let mixed = "\\x1b[31m日本語\\x1b[0m and text";
        assert_eq!(visible_width(mixed), 15);  // 6 (JP) + 9 ( and text)
    }

    #[test]
    fn malformed_escapes() {
        // Incomplete escape - should count visible parts
        assert_eq!(visible_width("\\x1b"), 0);
        assert_eq!(visible_width("\\x1b["), 0);
        assert_eq!(visible_width("text\\x1b"), 4);
    }

    // Performance fast path
    #[test]
    fn ascii_fast_path() {
        let ascii = "a".repeat(1000);
        assert_eq!(visible_width(&ascii), 1000);
    }
